export const getGuestIncidents = async (guestUserId) => {
  const q = query(
    collection(db, 'incidents'),
    where('guest.userId', '==', guestUserId),
    orderBy('createdAt', 'desc'),
    limit(20)
  )
  const snap = await getDocs(q)
  return snap.docs.map(d => d.data())
}

