// ── Draggable Wrapper ────────────────────────────────────────────────────
const DraggablePanel = ({ children, defaultPos }) => {
  const [pos, setPos] = useState(defaultPos)
  const [isDragging, setIsDragging] = useState(false)
  const [rel, setRel] = useState({ x: 0, y: 0 })

  useEffect(() => {
    const onMouseMove = (e) => {
      if (!isDragging) return
      setPos({ x: e.pageX - rel.x, y: e.pageY - rel.y })
    }
    const onMouseUp = () => setIsDragging(false)
    
    if (isDragging) {
      document.addEventListener('mousemove', onMouseMove)
      document.addEventListener('mouseup', onMouseUp)
    }
    return () => {
      document.removeEventListener('mousemove', onMouseMove)
      document.removeEventListener('mouseup', onMouseUp)
    }
  }, [isDragging, rel])

  const onMouseDown = (e) => {
    // Only drag if clicking the handle
    if (!e.target.closest('.drag-handle')) return
    setIsDragging(true)
    setRel({ x: e.pageX - pos.x, y: e.pageY - pos.y })
  }

  return (
    <div 
      style={{ position: 'fixed', left: pos.x, top: pos.y, zIndex: 9999 }}
      onMouseDown={onMouseDown}
      className={isDragging ? 'select-none opacity-90' : ''}
    >
      {children}
    </div>
  )
}

const computeAvgResponseTime = (incidents) => {
  const resolved = incidents.filter(
    i => i.status === 'resolved' && i.response?.acceptedAt && i.emergency?.triggeredAt
  )
  if (resolved.length === 0) return 'N/A'
  const avgMs = resolved.reduce((sum, i) => {
    const accepted = i.response.acceptedAt?.toMillis ? i.response.acceptedAt.toMillis() : (i.response.acceptedAt || 0)
    const triggered = i.emergency.triggeredAt?.toMillis ? i.emergency.triggeredAt.toMillis() : (i.emergency.triggeredAt || 0)
    return sum + Math.abs(accepted - triggered)
  }, 0) / resolved.length
  const avgSec = Math.floor(avgMs / 1000)
  return avgSec < 60
    ? `${avgSec}s`
    : `${Math.floor(avgSec / 60)}m ${avgSec % 60}s`
}
export default function AdminDashboard() {
  const { currentUser, userProfile } = useAuth()
  const hotelCode = userProfile?.adminProfile?.hotelCode

  // ── State ────────────────────────────────────────────────────────────────
  const [hotel, setHotel]             = useState(null)
  const [activeSOS, setActiveSOS]     = useState([])
  const [pendingCount, setPendingCount] = useState(0)
  const [staffList, setStaffList]     = useState([])
  const [incidents, setIncidents]     = useState([])
  const [openChatId, setOpenChatId]   = useState(null)
  const [activeWalkieChannel, setActiveWalkieChannel] = useState(`public_${hotelCode}`)
  const [loading, setLoading]         = useState(true)

  const todayStats = {
    resolvedCount: incidents.filter(i => i.status === 'resolved').length,
    avgResponseTime: computeAvgResponseTime(incidents),
    pendingApprovals: pendingCount,
  }

  // ── 1. Fetch hotel config from Firestore ────────────────────────────────
  useEffect(() => {
    if (!hotelCode) { setLoading(false); return }

    const fetchHotel = async () => {
      try {
        const snap = await getDoc(doc(db, 'hotels', hotelCode))
        if (snap.exists()) setHotel(snap.data())
      } catch (err) {
        console.error('Failed to fetch hotel:', err)
      } finally {
        setLoading(false)
      }
    }
    fetchHotel()
  }, [hotelCode])

  // ── 2. Listen to active SOS from Realtime Database ──────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const sosRef = ref(rtdb, `sos/${hotelCode}`)
    const unsub = onValue(sosRef, (snapshot) => {
      const data = snapshot.val()
      if (!data) { setActiveSOS([]); return }

      const sosList = Object.entries(data).map(([key, val]) => ({
        incidentId: key,
        ...val,
      }))
      setActiveSOS(sosList)
    })

    return () => unsub()
  }, [hotelCode])

  // ── 3. Listen to pending staff requests count from Firestore ───────────
  useEffect(() => {
    if (!hotelCode) return

    const q = query(
      collection(db, 'staff_requests'),
      where('hotelCode', '==', hotelCode),
      where('status', '==', 'pending')
    )
    const unsub = onSnapshot(q, (snap) => {
      setPendingCount(snap.size)
    })

    return () => unsub()
  }, [hotelCode])

  // ── 4. Listen to approved staff for this hotel ────────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const q = query(
      collection(db, 'users'),
      where('role', '==', 'staff'),
      where('staffProfile.hotelCode', '==', hotelCode)
    )
    const unsub = onSnapshot(q, (snap) => {
      setStaffList(snap.docs.map(d => ({ uid: d.id, ...d.data() })))
    })

    return () => unsub()
  }, [hotelCode])

  // ── 5. Listen to incidents for stats & AI context ─────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const q = query(
      collection(db, 'incidents'),
      where('hotelCode', '==', hotelCode)
    )
    const unsub = onSnapshot(q, (snap) => {
      setIncidents(snap.docs.map(d => ({ id: d.id, ...d.data() })))
    })

    return () => unsub()
  }, [hotelCode])

  // ── Resolve an emergency ───────────────────────────────────────────────
  const handleResolve = async (sosData) => {
    try {
      // 1. Remove from Realtime DB
      await remove(ref(rtdb, `sos/${hotelCode}/${sosData.incidentId}`))

      // 2. Write resolved record to Firestore incident_history
      await addDoc(collection(db, 'incident_history'), {
        ...sosData,
        hotelCode,
        status:          'resolved',
        resolvedAt:      serverTimestamp(),
        resolvedBy:      userProfile?.name || 'Admin',
        resolvedByUid:   currentUser.uid,
        resolutionNotes: '',
      })

      if (openChatId === sosData.incidentId) setOpenChatId(null)
      toast.success(`Incident in Room ${sosData.roomNumber} resolved.`)
    } catch (err) {
      console.error('Failed to resolve:', err)
      toast.error('Failed to resolve incident.')
    }
  }

  // ── Loading & no-hotel guard ───────────────────────────────────────────
  if (loading) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center">
        <span className="material-symbols-outlined animate-spin text-4xl text-blue-500">progress_activity</span>
      </div>
    )
  }

  if (!hotelCode) {
    return (
      <div className="min-h-screen bg-slate-100 flex items-center justify-center">
        <div className="text-center">
          <p className="text-slate-500 mb-4">No hotel registered yet.</p>
          <a href="/admin/register-hotel" className="text-blue-600 underline font-bold">Register your hotel</a>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-slate-100 dark:bg-surface flex transition-colors duration-300">
      <AdminSidebar hotelCode={hotelCode} pendingCount={pendingCount} />
      <main className="flex-1 flex flex-col h-screen min-w-0">
        <Header 
          title="Real-Time Dashboard" 
          subtitle={`${activeSOS.length} Active Emergencies`}
        />

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-8">
          <div className="max-w-6xl mx-auto">
            
            <div className="grid lg:grid-cols-3 gap-8">
              
              {/* Left Column: Grid */}
              <div className="lg:col-span-2 flex flex-col gap-6">
                <div className="bg-white dark:bg-surface-container-low rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700/50 overflow-hidden transition-colors">
                  <div className="px-6 py-4 border-b border-slate-100 dark:border-slate-700/50 flex items-center justify-between bg-slate-50 dark:bg-surface-container-highest transition-colors">
                    <h2 className="font-bold text-slate-800 dark:text-white flex items-center gap-2 transition-colors">
                      <span className="material-symbols-outlined text-blue-500 dark:text-blue-400">grid_on</span>
                      Live Facility Map
                    </h2>
                    <span className="text-xs font-bold px-3 py-1 bg-green-100 dark:bg-green-900/40 text-green-700 dark:text-green-400 rounded-full tracking-wide transition-colors">
                      System Online
                    </span>
                  </div>
                  <div className="p-6 overflow-x-auto flex justify-center">
                    <div className="inline-block max-w-full">
                      <RoomGrid 
                        floorLayout={hotel?.hotelConfig?.floorLayout || {}} 
                        activeSOS={activeSOS} 
                      />
                    </div>
                  </div>
                </div>
              </div>

              {/* Right Column: Active SOS & Chat */}
              <div className="flex flex-col gap-6 h-[calc(100vh-140px)]">
                {openChatId ? (
                  <div className="flex-1 flex flex-col min-h-0 relative z-20 shadow-2xl rounded-xl">
                     <button
                        onClick={() => setOpenChatId(null)}
                        className="absolute right-3 top-3 z-30 text-slate-400 dark:text-slate-500 hover:text-slate-800 dark:hover:text-white bg-white/80 dark:bg-surface-container-highest/80 rounded-full w-6 h-6 flex items-center justify-center transition-colors"
                     >
                       <span className="material-symbols-outlined text-sm">close</span>
                     </button>
                     <ChatWindow 
                        channelId={openChatId}
                        currentUser={currentUser}
                        userProfile={userProfile}
                        title={`Emergency Chat`}
                     />
                  </div>
                ) : (
                  <div className="flex-1 flex flex-col min-h-0 bg-white dark:bg-surface-container-low rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700/50 overflow-hidden transition-colors">
                    <div className="px-5 py-4 border-b border-slate-100 dark:border-slate-700/50 bg-slate-50 dark:bg-surface-container-highest flex items-center gap-2 shrink-0 transition-colors">
                      <span className="material-symbols-outlined text-red-500">emergency</span>
                      <h2 className="font-bold text-slate-800 dark:text-white transition-colors">Active Alerts</h2>
                      <span className="ml-auto bg-slate-200 dark:bg-surface-bright text-slate-700 dark:text-slate-300 text-xs font-bold px-2 py-0.5 rounded-full transition-colors">{activeSOS.length}</span>
                    </div>
                    <div className="p-4 overflow-y-auto flex-1 space-y-4 bg-slate-50/50 dark:bg-surface/50 transition-colors">
                      {activeSOS.length === 0 ? (
                        <div className="h-full flex flex-col items-center justify-center text-slate-400 dark:text-slate-500 transition-colors">
                          <span className="material-symbols-outlined text-5xl mb-3 opacity-30">check_circle</span>
                          <p className="font-medium text-sm">All clear.</p>
                          <p className="text-xs">No active emergencies.</p>
                        </div>
                      ) : (
                        activeSOS.map(sos => (
                          <IncidentCard 
                            key={sos.incidentId} 
                            sosData={sos} 
                            onViewChat={setOpenChatId}
                            onMarkResolved={handleResolve}
                          />
                        ))
                      )}
                    </div>
                  </div>
                )}
              </div>
            </div>
            
          </div>
        </div>
      </main>

      {/* Floating Walkie-Talkie Panel - Draggable */}
      <DraggablePanel defaultPos={{ x: 280, y: window.innerHeight - 450 }}>
        <div className="w-80 shadow-2xl rounded-xl">
          <WalkiePanelAdmin 
            hotelCode={hotelCode}
            activeSOS={activeSOS}
            staffList={staffList}
            currentUser={currentUser}
            userProfile={userProfile}
          />
        </div>
      </DraggablePanel>

      {/* Admin AI Assistant — floating bubble bottom right */}
      {/* Convert activeSOS array → { [roomNumber]: sosData } for AI context */}
      <AdminAIChatbot
        hotel={hotel}
        activeSOS={activeSOS.reduce((acc, s) => ({ ...acc, [s.roomNumber]: s }), {})}
        staffList={staffList}
        todayStats={todayStats}
        currentUser={currentUser}
      />
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useAuth } from '../../contexts/AuthContext'
import { db } from '../../firebase/config'
import { collection, query, where, orderBy, onSnapshot } from 'firebase/firestore'
import AdminSidebar from '../../components/layout/AdminSidebar'
import { formatDate, formatTime } from '../../utils/timeHelpers'
import { getEmergency } from '../../utils/emergencyHelpers'
import Header from '../../components/layout/Header'
import { useTheme } from '../../contexts/ThemeContext'

export default function IncidentHistory() {
  const { userProfile } = useAuth()
  const hotelCode = userProfile?.adminProfile?.hotelCode

  // ── Live state from Firestore ──────────────────────────────────────────
  const [history, setHistory]   = useState([])
  const [loading, setLoading]   = useState(true)

  // ── Listen to incident_history collection ──────────────────────────────
  useEffect(() => {
    if (!hotelCode) { setLoading(false); return }

    const q = query(
      collection(db, 'incident_history'),
      where('hotelCode', '==', hotelCode),
      orderBy('resolvedAt', 'desc')
    )

    const unsub = onSnapshot(q, (snap) => {
      const records = snap.docs.map(d => ({ id: d.id, ...d.data() }))
      setHistory(records)
      setLoading(false)
    }, (err) => {
      console.error('Incident history listener error:', err)
      setLoading(false)
    })

    return () => unsub()
  }, [hotelCode])

  // Helper to safely convert Firestore timestamp or millis to Date
  const toDate = (ts) => {
    if (!ts) return null
    if (ts.toDate) return ts.toDate()
    if (typeof ts === 'number') return new Date(ts)
    return new Date(ts)
  }

  const getDuration = (start, end) => {
    const startDate = toDate(start)
    const endDate   = toDate(end)
    if (!startDate || !endDate) return '-'
    const mins = Math.round((endDate - startDate) / 60000)
    return `${mins} mins`
  }

  const { darkMode } = useTheme()

  return (
    <div className="min-h-screen bg-slate-100 dark:bg-surface flex transition-colors duration-300">
      <AdminSidebar hotelCode={hotelCode} />
      
      <main className="flex-1 ml-64 flex flex-col h-screen min-w-0">
        <Header 
          title="Incident Log" 
          subtitle="Historical record of all resolved emergencies." 
          showNotifications={false}
        />
        
        <div className="flex-1 overflow-auto p-8">
          <div className="max-w-5xl mx-auto space-y-8">

          {loading ? (
            <div className="flex justify-center py-20">
              <span className="material-symbols-outlined animate-spin text-4xl text-blue-500">progress_activity</span>
            </div>
          ) : (
            <section className="bg-white dark:bg-surface-container-low rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700/50 overflow-hidden transition-colors">
               
               <div className="overflow-x-auto">
                 <table className="w-full text-left border-collapse">
                   <thead>
                     <tr className="bg-slate-50 dark:bg-surface-container-highest text-[10px] uppercase tracking-wider text-slate-500 dark:text-slate-400 border-b border-slate-200 dark:border-slate-700/50 transition-colors">
                       <th className="p-4 font-bold">Date & Time</th>
                       <th className="p-4 font-bold">Type</th>
                       <th className="p-4 font-bold">Room</th>
                       <th className="p-4 font-bold">Details</th>
                       <th className="p-4 font-bold">Resolution</th>
                     </tr>
                   </thead>
                   <tbody className="divide-y divide-slate-100 dark:divide-slate-700/30 text-sm">
                     {history.length === 0 ? (
                        <tr>
                          <td colSpan="5" className="p-8 text-center text-slate-400 dark:text-slate-500 italic transition-colors">No historical records found.</td>
                        </tr>
                     ) : history.map(incident => {
                       const emergency = getEmergency(incident.emergencyType)
                       const triggeredDate = toDate(incident.triggeredAt)
                       return (
                         <tr key={incident.id} className="hover:bg-slate-50/50 dark:hover:bg-surface-bright/50 transition-colors">
                           <td className="p-4 text-slate-500 dark:text-slate-400 font-medium">
                             {triggeredDate ? triggeredDate.toLocaleDateString() : '-'} <br/>
                             <span className="text-xs">{triggeredDate ? triggeredDate.toLocaleTimeString('en-IN', { hour:'2-digit', minute:'2-digit' }) : ''}</span>
                           </td>
                           <td className="p-4">
                              <div className="flex items-center gap-2">
                                 <span className="text-lg">{emergency?.icon}</span>
                                 <span className="font-bold text-slate-700 dark:text-slate-200">{emergency?.label}</span>
                              </div>
                           </td>
                           <td className="p-4 font-bold text-slate-800 dark:text-white text-base">
                             {incident.roomNumber}
                           </td>
                           <td className="p-4">
                             <p className="text-slate-700 dark:text-slate-300 font-semibold">{incident.guestName || '-'}</p>
                             <p className="text-xs text-slate-400 dark:text-slate-500 mt-1">Duration: {getDuration(incident.triggeredAt, incident.resolvedAt)}</p>
                           </td>
                           <td className="p-4 max-w-xs">
                             <p className="text-slate-800 dark:text-slate-300 line-clamp-2" title={incident.resolutionNotes}>{incident.resolutionNotes || '-'}</p>
                             <p className="text-[10px] uppercase tracking-wider text-slate-400 dark:text-slate-500 font-bold mt-1">By {incident.resolvedBy || 'Admin'}</p>
                           </td>
                         </tr>
                       )
                     })}
                   </tbody>
                 </table>
               </div>
            </section>
          )}



        </div>
      </div>
    </main>
  </div>
  )
}

import { useState, useEffect } from 'react'
import { useAuth } from '../../contexts/AuthContext'
import { db, rtdb } from '../../firebase/config'
import { collection, query, where, onSnapshot } from 'firebase/firestore'
import { ref, onValue, set, serverTimestamp, onDisconnect } from 'firebase/database'
import AdminSidebar from '../../components/layout/AdminSidebar'
import ChatWindow from '../../components/chat/ChatWindow'
import { useTheme } from '../../contexts/ThemeContext'

const DEFAULT_CHANNELS = [
  { id: 'general',    name: 'General',           icon: 'forum',       desc: 'Hotel-wide announcements & discussion' },
  { id: 'emergency',  name: 'Emergency Ops',     icon: 'emergency',   desc: 'Active emergency coordination' },
  { id: 'security',   name: 'Security',          icon: 'shield',      desc: 'Security team channel' },
  { id: 'medical',    name: 'Medical',           icon: 'medical_services', desc: 'Medical response team' },
  { id: 'fire_safety',name: 'Fire Safety',       icon: 'local_fire_department', desc: 'Fire safety team' },
  { id: 'maintenance',name: 'Maintenance',       icon: 'build',       desc: 'Facility & maintenance ops' },
]

export default function StaffChat() {
  const { currentUser, userProfile } = useAuth()
  const hotelCode = userProfile?.adminProfile?.hotelCode

  const [activeChannel, setActiveChannel] = useState('general')
  const [onlineUsers, setOnlineUsers]     = useState({})
  const [activeStaff, setActiveStaff]     = useState([])
  const [pendingCount, setPendingCount]   = useState(0)
  const [unreadCounts, setUnreadCounts]   = useState({})
  const [searchQuery, setSearchQuery]     = useState('')
  const [showMembers, setShowMembers]     = useState(true)

  // ── Listen to pending staff requests count ────────────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const q = query(
      collection(db, 'staff_requests'),
      where('hotelCode', '==', hotelCode),
      where('status', '==', 'pending')
    )
    const unsub = onSnapshot(q, (snap) => setPendingCount(snap.size))
    return () => unsub()
  }, [hotelCode])

  // ── Set own presence in RTDB ──────────────────────────────────────────
  useEffect(() => {
    if (!currentUser || !hotelCode) return

    const presenceRef = ref(rtdb, `presence/${hotelCode}/${currentUser.uid}`)
    const connectedRef = ref(rtdb, '.info/connected')

    const unsub = onValue(connectedRef, (snap) => {
      if (snap.val() === true) {
        set(presenceRef, {
          name:   userProfile?.name || 'Admin',
          role:   'admin',
          online: true,
          lastSeen: Date.now(),
        })
        onDisconnect(presenceRef).set({
          name:   userProfile?.name || 'Admin',
          role:   'admin',
          online: false,
          lastSeen: Date.now(),
        })
      }
    })

    return () => {
      unsub()
      set(presenceRef, {
        name:   userProfile?.name || 'Admin',
        role:   'admin',
        online: false,
        lastSeen: Date.now(),
      })
    }
  }, [currentUser, hotelCode, userProfile])

  // ── Listen to online presence ─────────────────────────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const presRef = ref(rtdb, `presence/${hotelCode}`)
    const unsub = onValue(presRef, (snap) => {
      setOnlineUsers(snap.val() || {})
    })

    return () => unsub()
  }, [hotelCode])

  // ── Listen to active staff from Firestore ─────────────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const q = query(
      collection(db, 'users'),
      where('role', '==', 'staff'),
      where('staffProfile.hotelCode', '==', hotelCode),
      where('staffProfile.isApproved', '==', true)
    )
    const unsub = onSnapshot(q, (snap) => {
      setActiveStaff(snap.docs.map(d => ({ id: d.id, ...d.data() })))
    })

    return () => unsub()
  }, [hotelCode])

  // ── Listen for unread counts per channel ──────────────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const listeners = DEFAULT_CHANNELS.map(ch => {
      const msgRef = ref(rtdb, `chats/${hotelCode}_${ch.id}/messages`)
      return onValue(msgRef, (snap) => {
        const data = snap.val()
        const count = data ? Object.keys(data).length : 0
        setUnreadCounts(prev => ({ ...prev, [ch.id]: count }))
      })
    })

    return () => listeners.forEach(unsub => unsub())
  }, [hotelCode])

  const channelId = hotelCode ? `${hotelCode}_${activeChannel}` : null
  const activeChannelData = DEFAULT_CHANNELS.find(c => c.id === activeChannel)

  const onlineCount = Object.values(onlineUsers).filter(u => u.online).length
  const totalMembers = activeStaff.length + 1 // +1 for admin

  const filteredStaff = activeStaff.filter(s =>
    s.name?.toLowerCase().includes(searchQuery.toLowerCase())
  )

  // Role color helpers
  const getRoleColor = (role) => {
    const colors = {
      admin:       'bg-blue-500',
      fire_safety: 'bg-red-500',
      medical:     'bg-emerald-500',
      security:    'bg-amber-500',
      general:     'bg-purple-500',
    }
    return colors[role] || 'bg-slate-400'
  }

  const getRoleBadge = (role) => {
    const badges = {
      admin:       'bg-blue-500/10 text-blue-400 ring-blue-500/20',
      fire_safety: 'bg-red-500/10 text-red-400 ring-red-500/20',
      medical:     'bg-emerald-500/10 text-emerald-400 ring-emerald-500/20',
      security:    'bg-amber-500/10 text-amber-400 ring-amber-500/20',
      general:     'bg-purple-500/10 text-purple-400 ring-purple-500/20',
    }
    return badges[role] || 'bg-slate-500/10 text-slate-400 ring-slate-500/20'
  }

  const { darkMode } = useTheme()

  return (
    <div className={`min-h-screen flex transition-colors duration-300 ${darkMode ? 'bg-surface text-on-surface' : 'bg-slate-100 text-slate-800'}`}>
      <AdminSidebar hotelCode={hotelCode} pendingCount={pendingCount} />

      <main className="flex-1 ml-64 flex h-screen overflow-hidden">

        {/* ── Channel Sidebar ──────────────────────────────────────────── */}
        <div className={`w-72 border-r flex flex-col shrink-0 transition-colors duration-300 ${darkMode ? 'bg-surface-container-low border-slate-800/80' : 'bg-white border-slate-200'}`}>
          {/* Channel header */}
          <div className={`p-5 border-b transition-colors ${darkMode ? 'border-slate-800/60' : 'border-slate-100'}`}>
            <div className="flex items-center gap-2.5 mb-1">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-blue-500/20">
                <span className="material-symbols-outlined text-white text-[16px]">chat</span>
              </div>
              <div>
                <h2 className={`font-bold text-sm tracking-tight transition-colors ${darkMode ? 'text-white' : 'text-slate-800'}`}>Staff Chat</h2>
                <p className="text-slate-500 text-[10px] font-medium">{onlineCount} online · {totalMembers} members</p>
              </div>
            </div>
          </div>

          {/* Channels list */}
          <div className="flex-1 overflow-y-auto p-3 space-y-0.5">
            <p className="text-slate-500 text-[9px] uppercase tracking-[0.15em] font-bold px-3 py-2">Channels</p>
            {DEFAULT_CHANNELS.map(ch => {
              const isActive = activeChannel === ch.id
              return (
                <button
                  key={ch.id}
                  onClick={() => setActiveChannel(ch.id)}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-200 group relative ${
                    isActive
                      ? (darkMode ? 'bg-blue-600/15 text-blue-400' : 'bg-blue-50 text-blue-600')
                      : (darkMode ? 'text-slate-400 hover:bg-white/5 hover:text-slate-300' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900')
                  }`}
                >
                  {isActive && (
                    <div className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-5 bg-blue-500 rounded-r-full" />
                  )}
                  <span className={`material-symbols-outlined text-[18px] transition ${
                    isActive ? (darkMode ? 'text-blue-400' : 'text-blue-600') : 'text-slate-400 group-hover:text-slate-600'
                  }`}>{ch.icon}</span>
                  <span className="truncate">{ch.name}</span>
                  {ch.id === 'emergency' && (
                    <span className="ml-auto w-2 h-2 bg-red-500 rounded-full animate-pulse" />
                  )}
                </button>
              )
            })}
          </div>

          {/* User info footer */}
          <div className={`p-4 border-t transition-colors ${darkMode ? 'border-slate-800/60 bg-slate-900/50' : 'border-slate-100 bg-slate-50'}`}>
            <div className="flex items-center gap-3">
              <div className="relative">
