                </h3>
                <p className="text-slate-500 text-xs font-medium">{activeChannelData?.desc}</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <button className={`w-9 h-9 rounded-lg flex items-center justify-center transition ${darkMode ? 'bg-slate-800/80 hover:bg-slate-700 text-slate-400 hover:text-slate-300' : 'bg-slate-50 hover:bg-slate-100 text-slate-500 hover:text-slate-700'}`}>
                <span className="material-symbols-outlined text-[18px]">search</span>
              </button>
              <button className={`w-9 h-9 rounded-lg flex items-center justify-center transition ${darkMode ? 'bg-slate-800/80 hover:bg-slate-700 text-slate-400 hover:text-slate-300' : 'bg-slate-50 hover:bg-slate-100 text-slate-500 hover:text-slate-700'}`}>
                <span className="material-symbols-outlined text-[18px]">push_pin</span>
              </button>
              <button
                onClick={() => setShowMembers(!showMembers)}
                className={`w-9 h-9 rounded-lg flex items-center justify-center transition ${
                  showMembers 
                    ? (darkMode ? 'bg-blue-500/15 text-blue-400' : 'bg-blue-50 text-blue-600') 
                    : (darkMode ? 'bg-slate-800/80 hover:bg-slate-700 text-slate-400 hover:text-slate-300' : 'bg-slate-100 text-slate-500 hover:text-slate-700')
