                      </span>
                    </div>
                  </div>
                ))}
            </div>
          </div>
        )}
      </main>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useAuth } from '../../contexts/AuthContext'
import { db } from '../../firebase/config'
import { collection, query, where, onSnapshot, doc, updateDoc, deleteDoc, serverTimestamp } from 'firebase/firestore'
import AdminSidebar from '../../components/layout/AdminSidebar'
import toast from 'react-hot-toast'
import { formatDate } from '../../utils/timeHelpers'
import Header from '../../components/layout/Header'
import { useTheme } from '../../contexts/ThemeContext'

export default function StaffManagement() {
  const { currentUser, userProfile } = useAuth()
  const hotelCode = userProfile?.adminProfile?.hotelCode

  // ── Live state from Firestore ──────────────────────────────────────────
  const [pendingRequests, setPendingRequests] = useState([])
  const [activeStaff, setActiveStaff]         = useState([])

  // ── 1. Listen to pending staff requests ────────────────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const q = query(
      collection(db, 'staff_requests'),
      where('hotelCode', '==', hotelCode),
      where('status', '==', 'pending')
    )
    const unsub = onSnapshot(q, (snap) => {
      const requests = snap.docs.map(d => ({ id: d.id, ...d.data() }))
      setPendingRequests(requests)
    })

    return () => unsub()
  }, [hotelCode])

  // ── 2. Listen to approved staff for this hotel ─────────────────────────
  useEffect(() => {
    if (!hotelCode) return

    const q = query(
      collection(db, 'users'),
      where('role', '==', 'staff'),
      where('staffProfile.hotelCode', '==', hotelCode),
      where('staffProfile.isApproved', '==', true)
    )
    const unsub = onSnapshot(q, (snap) => {
      const staff = snap.docs.map(d => ({ id: d.id, ...d.data() }))
      setActiveStaff(staff)
    })

    return () => unsub()
  }, [hotelCode])

  // ── Approve staff ──────────────────────────────────────────────────────
  const handleApprove = async (req) => {
    try {
      // 1. Update the user doc → staffProfile.isApproved = true
      await updateDoc(doc(db, 'users', req.staffId), {
        'staffProfile.isApproved': true,
        'staffProfile.approvedBy': currentUser.uid,
        'staffProfile.approvedAt': serverTimestamp(),
      })

      // 2. Update the staff_requests doc status
      await updateDoc(doc(db, 'staff_requests', req.staffId), {
        status: 'approved',
        approvedBy: currentUser.uid,
        approvedAt: serverTimestamp(),
      })

      toast.success(`${req.staffName} approved.`)
    } catch (err) {
      console.error('Approve failed:', err)
      toast.error('Failed to approve staff.')
    }
  }

  // ── Reject staff ──────────────────────────────────────────────────────
  const handleReject = async (req) => {
    try {
      // Update status in staff_requests
      await updateDoc(doc(db, 'staff_requests', req.staffId), {
        status: 'rejected',
        rejectedBy: currentUser.uid,
        rejectedAt: serverTimestamp(),
      })

      toast.error(`${req.staffName} rejected.`)
    } catch (err) {
      console.error('Reject failed:', err)
      toast.error('Failed to reject staff.')
    }
  }

  // ── Remove staff ──────────────────────────────────────────────────────
  const handleRemove = async (staffUid) => {
    try {
      // Revoke approval
      await updateDoc(doc(db, 'users', staffUid), {
        'staffProfile.isApproved': false,
        'staffProfile.approvedBy': null,
        'staffProfile.approvedAt': null,
      })
      toast.success('Staff removed from active roster.')
    } catch (err) {
      console.error('Remove failed:', err)
      toast.error('Failed to remove staff.')
    }
  }
  
  const getRoleBadge = (role) => {
    const roles = {
      'fire_safety': 'bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400 border-red-100 dark:border-red-900/30',
      'medical': 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-400 border-emerald-100 dark:border-emerald-900/30',
      'security': 'bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-400 border-blue-100 dark:border-blue-900/30',
    }

    return <span className={`px-2.5 py-0.5 text-[10px] uppercase tracking-wider font-bold rounded-md border transition-colors ${roles[role] || 'bg-slate-100 dark:bg-surface-container-high text-slate-700 dark:text-slate-300 border-slate-200 dark:border-slate-700/50'}`}>{role?.replace('_', ' ')}</span>
  }

  const { darkMode } = useTheme()

  return (
    <div className="min-h-screen bg-slate-100 dark:bg-surface flex transition-colors duration-300">
      <AdminSidebar hotelCode={hotelCode} pendingCount={pendingRequests.length} />
      
      <main className="flex-1 ml-64 flex flex-col h-screen min-w-0">
        <Header 
          title="Staff Management" 
          subtitle="Approve and manage your emergency response team."
        />

        <div className="flex-1 overflow-auto p-8">
          <div className="max-w-5xl mx-auto space-y-8">

          {/* Pending Requests */}
          {pendingRequests.length > 0 && (
            <section className="bg-white dark:bg-surface-container-low rounded-2xl shadow-sm border border-amber-200 dark:border-amber-900/30 overflow-hidden transition-colors">
               <div className="bg-amber-50 dark:bg-amber-900/10 px-6 py-4 border-b border-amber-100 dark:border-amber-900/20 flex items-center gap-3 transition-colors">
                  <span className="material-symbols-outlined text-amber-500">pending_actions</span>
                  <h2 className="font-bold text-amber-800 dark:text-amber-200">{pendingRequests.length} Pending Staff Requests</h2>
               </div>
               <div className="divide-y divide-slate-100 dark:divide-slate-700/30 p-2 transition-colors">
                 {pendingRequests.map(req => (
                   <div key={req.staffId} className="flex items-center justify-between p-4 hover:bg-slate-50 dark:hover:bg-surface-bright/50 transition rounded-xl">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-full bg-slate-200 dark:bg-surface-container-highest flex items-center justify-center font-bold text-slate-500 dark:text-slate-400 transition-colors">
                          {req.staffName?.charAt(0)}
                        </div>
                        <div>
                          <p className="font-bold text-slate-800 dark:text-white text-sm transition-colors">{req.staffName}</p>
                          <p className="text-xs text-slate-500 dark:text-slate-400 transition-colors">{req.staffEmail}</p>
                        </div>
                        <div className="ml-4">
                          {getRoleBadge(req.designation)}
                        </div>
                        <div className="ml-4 text-xs text-slate-400">
                           Applied {formatDate(req.requestedAt)}
                        </div>
                      </div>
                      <div className="flex gap-2">
                         <button onClick={() => handleApprove(req)} className="px-4 py-2 bg-green-500 text-white rounded-lg text-sm font-bold hover:bg-green-600 transition flex items-center gap-1">
                           <span className="material-symbols-outlined text-[16px]">check</span> Approve
                         </button>
                         <button onClick={() => handleReject(req)} className="px-4 py-2 bg-slate-100 text-slate-600 rounded-lg text-sm font-bold hover:bg-slate-200 hover:text-red-600 transition flex items-center gap-1">
                           <span className="material-symbols-outlined text-[16px]">close</span> Reject
                         </button>
                      </div>
                   </div>
                 ))}
               </div>
            </section>
          )}

          {/* Active Staff Table */}
          <section className="bg-white dark:bg-surface-container-low rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700/50 overflow-hidden transition-colors">
             <div className="px-6 py-4 border-b border-slate-100 dark:border-slate-700/50 bg-slate-50 dark:bg-surface-container-highest flex items-center gap-3 transition-colors">
                <span className="material-symbols-outlined text-blue-500 dark:text-blue-400">group</span>
                <h2 className="font-bold text-slate-800 dark:text-white">Active Staff Registry</h2>
             </div>
             
             <div className="overflow-x-auto">
               <table className="w-full text-left border-collapse">
                 <thead>
                   <tr className="bg-slate-50 dark:bg-surface-container-highest text-[10px] uppercase tracking-wider text-slate-500 dark:text-slate-400 border-b border-slate-200 dark:border-slate-700/50 transition-colors">
                     <th className="p-4 font-bold">Name</th>
                     <th className="p-4 font-bold">Designation</th>
                     <th className="p-4 font-bold">Status</th>
                     <th className="p-4 font-bold">Active Incident</th>
                     <th className="p-4 font-bold text-right">Actions</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100 dark:divide-slate-700/30 text-sm transition-colors">
                   {activeStaff.length === 0 ? (
                      <tr>
                        <td colSpan="5" className="p-8 text-center text-slate-400 dark:text-slate-500 italic transition-colors">No active staff members.</td>
                      </tr>
                   ) : activeStaff.map(staff => (
                     <tr key={staff.id} className="hover:bg-slate-50/50 dark:hover:bg-surface-bright/50 transition-colors">
                       <td className="p-4 font-bold text-slate-800 dark:text-white flex items-center gap-3 transition-colors">
                         <div className="w-8 h-8 rounded-full bg-blue-100 dark:bg-blue-900/50 text-blue-700 dark:text-blue-300 flex items-center justify-center font-bold text-xs border border-blue-200 dark:border-blue-800 transition-colors">
                            {staff.name?.charAt(0)}
                          </div>
                          {staff.name}
                       </td>
                       <td className="p-4">
                         {getRoleBadge(staff.staffProfile?.designation)}
                       </td>
                       <td className="p-4">
                         {staff.staffProfile?.isOnDuty ? (
                           <span className="inline-flex items-center gap-1.5 px-2 py-1 rounded bg-green-50 text-green-700 text-xs font-bold w-max">
                             <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span> On Duty
                           </span>
                         ) : (
                           <span className="inline-flex items-center gap-1.5 px-2 py-1 rounded bg-slate-100 text-slate-500 text-xs w-max font-bold">
                             <span className="w-1.5 h-1.5 bg-slate-400 rounded-full"></span> Off Duty
                           </span>
                         )}
                       </td>
                       <td className="p-4 text-slate-500">
                         {staff.staffProfile?.activeIncidents?.length > 0 ? (
                           <span className="text-red-500 font-medium">Active ({staff.staffProfile.activeIncidents.length})</span>
                         ) : '-'}
                       </td>
                       <td className="p-4 text-right">
                         <button onClick={() => handleRemove(staff.id)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-lg transition" title="Remove Staff">
                           <span className="material-symbols-outlined text-[20px]">person_remove</span>
                         </button>
                       </td>
                     </tr>
                   ))}
                 </tbody>
               </table>
             </div>
          </section>

          </div>
        </div>
      </main>
    </div>
  )
}

// src/pages/guest/GuestDashboard.jsx
// Main dashboard — fully wired to Firebase backend
// SOS trigger → Realtime DB + Firestore + Chat room auto-creation
// Live listener via useSOSListener hook
// Gemini AI chatbot auto-opens with incident context

import { useState, useEffect, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'

import { useAuth }        from '../../contexts/AuthContext'
import { useSOSListener } from '../../hooks/useSOSListener'
import { triggerSOS }     from '../../services/sosService'
import { sendMessage,
         subscribeToChat } from '../../services/chatService'
import { checkOutGuest }  from '../../services/hotelService'
import { getHotelDoc }    from '../../firebase/firestore'

import GuestSidebar  from '../../components/guest/GuestSidebar'
import SOSButton     from '../../components/sos/SOSButton'
import GuestGeminiChatbot from '../../components/guest/GuestGeminiChatbot'
import { useTheme } from '../../contexts/ThemeContext'
import Header from '../../components/layout/Header'

export default function GuestDashboard() {
  const navigate  = useNavigate()
  const { darkMode } = useTheme()
  const { currentUser, userProfile, refreshProfile } = useAuth()

  const hotelCode  = userProfile?.guestProfile?.currentHotelCode
  const roomNumber = userProfile?.guestProfile?.currentRoomNumber

  // ── Realtime SOS listener ──────────────────────────────────────
  const { activeSOS, incidentId } = useSOSListener(hotelCode, roomNumber)

  // ── Local UI State ─────────────────────────────────────────────
  const [sidebarOpen,     setSidebarOpen]     = useState(false)
  const [hotelData,       setHotelData]       = useState(null)
  const [emergencyContext, setEmergencyContext] = useState(null)
  const [showChat,        setShowChat]        = useState(false)
  const [chatMessages,    setChatMessages]    = useState([])
  const [chatInput,       setChatInput]       = useState('')
  const [sosLoading,      setSosLoading]      = useState(false)
  const chatEndRef = useRef(null)

  // ── Fetch hotel data once on mount ─────────────────────────────
  useEffect(() => {
    if (!hotelCode) return
    getHotelDoc(hotelCode).then(snap => {
      if (snap.exists()) setHotelData(snap.data())
    })
  }, [hotelCode])

  // ── Redirect if not staying ─────────────────────────────────────
  useEffect(() => {
    if (userProfile && !userProfile.guestProfile?.isCurrentlyStaying) {
      navigate('/guest/mode-select', { replace: true })
    }
  }, [userProfile])

  // ── Update emergency context when SOS becomes active ───────────
  useEffect(() => {
    if (activeSOS && !emergencyContext) {
      setEmergencyContext({
        type:       activeSOS.emergencyType,
        roomNumber: activeSOS.roomNumber,
        guestName:  userProfile?.name,
      })
    }
    if (!activeSOS && emergencyContext) {
      // Resolved!
      toast.success('✅ Emergency resolved. Thank you for your patience.', { duration: 6000 })
      setEmergencyContext(null)
      setShowChat(false)
    }
    if (activeSOS?.status === 'assigned' && activeSOS?.assignedStaffName) {
      toast.success(`✅ ${activeSOS.assignedStaffName} is on the way!`, { duration: 5000, id: 'staff-assigned' })
    }
  }, [activeSOS])

  // ── Subscribe to chat messages when incident exists ────────────
  useEffect(() => {
    if (!incidentId) return
    const unsub = subscribeToChat(incidentId, setChatMessages)
    return unsub
  }, [incidentId])

  // ── Auto-scroll chat ───────────────────────────────────────────
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [chatMessages])

  // ── SOS Trigger ────────────────────────────────────────────────
  const handleTriggerSOS = async (emergencyType) => {
    if (activeSOS) return
    setSosLoading(true)
    try {
      await triggerSOS(currentUser, userProfile, emergencyType)
      setShowChat(true)
      toast.success('🆘 SOS sent! Help is being dispatched immediately.', { duration: 8000 })
    } catch (err) {
      console.error(err)
      toast.error('SOS failed. Check your connection and try again.')
    } finally {
      setSosLoading(false)
    }
  }

  // ── Send Chat Message ──────────────────────────────────────────
  const handleSendChat = async () => {
    if (!chatInput.trim() || !incidentId) return
    try {
      await sendMessage(incidentId, {
        uid:  currentUser.uid,
        name: userProfile.name,
        role: 'guest',
      }, chatInput.trim())
      setChatInput('')
    } catch (err) {
      toast.error('Message failed to send.')
    }
  }

  // ── Check Out ──────────────────────────────────────────────────
  const handleCheckOut = async () => {
    if (!window.confirm('Check out and remove emergency access?')) return
    try {
      await checkOutGuest(currentUser.uid)
      await refreshProfile()
      navigate('/guest/mode-select')
      toast.success('Checked out. Stay safe!')
    } catch {
      toast.error('Check-out failed.')
    }
  }

  return (
    <div className={`flex h-screen overflow-hidden transition-colors duration-300 ${darkMode ? 'bg-surface text-on-surface' : 'bg-slate-50 text-slate-800'}`}>

      {/* Mobile Sidebar Overlay */}
      {sidebarOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40 md:hidden" onClick={() => setSidebarOpen(false)} />
      )}

      {/* Sidebar */}
      <GuestSidebar 
        hotelData={hotelData} 
        isOpen={sidebarOpen}
        onClose={() => setSidebarOpen(false)} 
        onCheckOut={handleCheckOut} 
      />

      {/* Main Pane */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden min-w-0 md:ml-64">
        
        <Header 
           title="Emergency Dashboard"
           subtitle={`Room ${roomNumber} • ${hotelData?.hotelName || 'Crisis Bridge'}`}
           onMenuClick={() => setSidebarOpen(true)}
        />

        <div className="flex-1 overflow-y-auto p-4 md:p-8 flex flex-col items-center justify-center relative gap-8 z-0">

          {/* Dynamic bg glow based on theme */}
          <div className="absolute inset-0 pointer-events-none -z-10 overflow-hidden hidden md:block">
            {activeSOS ? (
              <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-red-600/10 rounded-full blur-[150px] animate-pulse" />
            ) : (
              <>
                <div className="absolute top-0 right-0 w-[600px] h-[600px] bg-indigo-500/5 rounded-full blur-[120px]" />
                <div className="absolute bottom-0 left-1/4 w-[500px] h-[500px] bg-purple-500/5 rounded-full blur-[120px]" />
              </>
            )}
          </div>

          <div className="max-w-3xl w-full flex flex-col items-center gap-8">

            {/* ── ACTIVE SOS PANEL ── */}
            {activeSOS && (
              <div className="w-full bg-surface-container-high/80 dark:bg-[#130E14]/80 backdrop-blur-2xl border border-red-500/30 shadow-[0_0_60px_rgba(239,68,68,0.15)] rounded-[2rem] p-6 sm:p-8 relative overflow-hidden animate-in fade-in slide-in-from-top-8 duration-500">
                <div className="absolute top-0 left-0 w-full h-1.5" style={{ backgroundImage: 'repeating-linear-gradient(45deg,#ef4444,#ef4444 10px,#b91c1c 10px,#b91c1c 20px)' }} />

                <div className="flex flex-col md:flex-row items-center md:items-start gap-6 relative z-10">
                  <div className="w-20 h-20 bg-red-600/20 border border-red-500/50 rounded-2xl flex items-center justify-center text-4xl shadow-[0_0_30px_rgba(239,68,68,0.4)] animate-pulse shrink-0">🚨</div>
                  <div className="flex-1 text-center md:text-left">
                    <h2 className="text-red-500 font-black text-2xl md:text-3xl mb-1 uppercase flex items-center justify-center md:justify-start gap-3">
                      {activeSOS.emergencyType} EMERGENCY
                      <span className="w-3 h-3 bg-red-500 rounded-full animate-ping" />
                    </h2>
                    <p className="text-slate-300 font-medium mb-5 text-lg">
                      Dispatch to <span className="text-white font-bold">Room {roomNumber}</span> in progress
                    </p>

                    {activeSOS.status === 'assigned' ? (
                      <div className="bg-emerald-500/10 border border-emerald-500/30 text-emerald-400 px-5 py-4 rounded-2xl font-bold flex items-center justify-center md:justify-start gap-3 mb-5">
                        <span className="text-2xl">✓</span> {activeSOS.assignedStaffName} has accepted & is en route!
                      </div>
                    ) : (
                      <div className="bg-red-500/10 border border-red-500/20 text-red-400 px-5 py-4 rounded-2xl font-bold flex items-center justify-center md:justify-start gap-3 mb-5">
                        <span className="w-5 h-5 border-2 border-red-400 border-t-transparent rounded-full animate-spin" />
                        Locating nearest responder…
                      </div>
                    )}

                    <div className="flex flex-col sm:flex-row gap-3">
                      <button onClick={() => setShowChat(v => !v)}
                        className="flex-1 bg-white/5 hover:bg-white/10 border border-white/10 text-white px-5 py-3.5 rounded-xl font-bold flex items-center justify-center gap-2 transition-all">
                        💬 {showChat ? 'Hide Chat' : 'Open Comm Link'}
                      </button>
                    </div>
                    <p className="mt-5 text-red-400 text-sm font-semibold bg-red-500/10 inline-block px-3 py-1.5 rounded-lg border border-red-500/20">
                      ⚠️ DO NOT LEAVE THE ROOM UNLESS DIRECTED
                    </p>
                  </div>
                </div>
              </div>
            )}

            {/* ── LIVE CHAT PANEL ── */}
            {showChat && incidentId && (
              <div className="w-full bg-[#0B0F19]/90 backdrop-blur-2xl border border-white/10 rounded-[2rem] overflow-hidden shadow-2xl animate-in fade-in slide-in-from-bottom-4">
                <div className="bg-gradient-to-r from-slate-800/60 to-slate-900/60 px-6 py-4 border-b border-white/5 flex items-center gap-3">
                  <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.8)]" />
                  <h3 className="text-white font-bold tracking-wide">Emergency Communication Channel</h3>
                  <span className="ml-auto text-[10px] text-slate-500 font-mono tracking-widest">{incidentId?.slice(-8).toUpperCase()}</span>
                </div>
                <div className="h-64 overflow-y-auto p-5 space-y-3">
                  {chatMessages.map((msg, i) => (
                    <div key={i} className={`flex ${msg.senderRole === 'guest' ? 'justify-end' : 'justify-start'} ${msg.type === 'system_message' ? 'justify-center' : ''}`}>
                      {msg.type === 'system_message' ? (
                        <span className="text-[11px] text-slate-500 border border-white/5 bg-white/[0.02] px-3 py-1 rounded-full">{msg.message}</span>
                      ) : (
                        <div className={`max-w-[75%] rounded-2xl px-4 py-2.5 text-sm ${msg.senderRole === 'guest' ? 'bg-indigo-600 text-white rounded-br-sm' : 'bg-slate-800/80 text-slate-200 rounded-bl-sm border border-white/5'}`}>
                          <p className="text-[10px] font-bold opacity-60 mb-1 uppercase tracking-wider">{msg.senderName}</p>
                          {msg.message}
                        </div>
                      )}
                    </div>
                  ))}
                  <div ref={chatEndRef} />
                </div>
                <div className="p-4 border-t border-white/5 flex gap-2">
                  <input
                    value={chatInput}
                    onChange={e => setChatInput(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && handleSendChat()}
                    placeholder="Type a message to staff..."
                    className="flex-1 bg-white/[0.03] border border-white/10 rounded-full px-4 py-2.5 text-sm text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-indigo-500/50"
                  />
                  <button onClick={handleSendChat}
                    className="bg-indigo-600 hover:bg-indigo-500 text-white w-10 h-10 rounded-full flex items-center justify-center transition border border-indigo-400/30 shadow-md shrink-0">↑</button>
                </div>
              </div>
            )}

            {/* ── SOS BUTTONS (disabled when SOS active) ── */}
            <div className={`w-full transition-all duration-700 ${activeSOS ? 'opacity-20 pointer-events-none scale-[0.98] blur-sm' : 'opacity-100'}`}>
              <div className="text-center mb-16">
                <div className="inline-block px-4 py-1.5 rounded-full bg-emerald-500/10 border border-emerald-500/20 text-emerald-400 text-xs font-bold tracking-widest uppercase mb-6">
                  SafeGuard Grid • Online
                </div>
                <h1 className="text-5xl md:text-6xl font-black text-white tracking-tighter mb-4">Require Assistance?</h1>
                <p className="text-slate-400 text-lg font-medium">Hold any module for 2 seconds to dispatch immediate support.</p>
              </div>

              <div className="flex justify-center mb-16 relative">
                <div className="absolute inset-0 bg-purple-600/10 blur-[80px] rounded-full z-0" />
                <SOSButton type="common" size="large" disabled={!!activeSOS || sosLoading} onTrigger={handleTriggerSOS} />
              </div>

              <div className="flex flex-wrap justify-center gap-6 sm:gap-8 bg-[#0B0F19]/40 backdrop-blur-2xl p-6 sm:p-8 rounded-[3rem] border border-white/5 shadow-2xl w-full max-w-2xl mx-auto">
                <SOSButton type="fire"     disabled={!!activeSOS || sosLoading} onTrigger={handleTriggerSOS} />
                <SOSButton type="medical"  disabled={!!activeSOS || sosLoading} onTrigger={handleTriggerSOS} />
                <SOSButton type="security" disabled={!!activeSOS || sosLoading} onTrigger={handleTriggerSOS} />
              </div>
            </div>

          </div>
        </div>
      </main>

      <GuestGeminiChatbot emergencyContext={emergencyContext} />
    </div>
  )
}

import { useState, useEffect, useRef, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../../contexts/AuthContext'
import { db, rtdb } from '../../firebase/config'
import {
  doc, getDoc, updateDoc, onSnapshot,
  serverTimestamp, arrayUnion, arrayRemove,
  collection, query, where, getDocs
} from 'firebase/firestore'
import {
  ref, set, onValue, off, update, push, remove, onDisconnect
} from 'firebase/database'
import { getEmergency } from '../../utils/emergencyHelpers'
import { timeAgo } from '../../utils/timeHelpers'
import StaffSidebar from '../../components/staff/StaffSidebar'
import SOSPopup from '../../components/staff/SOSPopup'
import ChatWindow from '../../components/chat/ChatWindow'
import Header from '../../components/layout/Header'
import { useTheme } from '../../contexts/ThemeContext'
import toast from 'react-hot-toast'

/* ── Tab names from crisis-bridge prototype ── */
const TAB_EMOJIS = ['🏨', '🚨', '💬', '📡', '📋']
const TAB_IDS    = ['grid', 'incident', 'chat', 'group', 'history']

export default function StaffDashboard() {
  const { currentUser, userProfile } = useAuth()
  const navigate = useNavigate()

  // ── State ──────────────────────────────────────────────────────────────
  const [hotel,        setHotel]        = useState(null)
  const [activeSOS,    setActiveSOS]    = useState({})
  const [myIncident,   setMyIncident]   = useState(null)
  const [newSOSAlert,  setNewSOSAlert]  = useState(null)
  const [isOnDuty,     setIsOnDuty]     = useState(false)
  const [activeTab,    setActiveTab]    = useState('grid')
  const [clock,        setClock]        = useState('')
  const [assignmentStep, setAssignmentStep] = useState(1) // 1=assigned, 2=arrived, 3=resolved
  const [showResolveForm, setShowResolveForm] = useState(false)
  const [resolveNotes, setResolveNotes] = useState('')
  const [triggeredSeconds, setTriggeredSeconds] = useState(0)
  const [expandedHistory, setExpandedHistory] = useState(null)
  const [historyFilter, setHistoryFilter] = useState({ type: 'all', status: 'all' })
  const [incidentHistory, setIncidentHistory] = useState([])
  const [toast_msg, setToastMsg] = useState(null)

  const isOnDutyRef = useRef(isOnDuty)
  isOnDutyRef.current = isOnDuty

  // ── Live clock ────────────────────────────────────────────────────────
  useEffect(() => {
    const tick = () => {
      const now = new Date()
      setClock(now.toLocaleTimeString('en-GB', { hour12: false }))
    }
    tick()
    const id = setInterval(tick, 1000)
    return () => clearInterval(id)
  }, [])

  // ── Timer for triggered assignment ────────────────────────────────────
  useEffect(() => {
    if (myIncident && assignmentStep < 3) {
      const id = setInterval(() => setTriggeredSeconds(s => s + 1), 1000)
      return () => clearInterval(id)
    }
  }, [myIncident, assignmentStep])

  // ── Toast auto-dismiss ────────────────────────────────────────────────
  useEffect(() => {
    if (toast_msg) {
      const id = setTimeout(() => setToastMsg(null), 3000)
      return () => clearTimeout(id)
    }
  }, [toast_msg])

  // ── Helper: does this SOS match my designation? ────────────────────────
  const isSOSForMe = useCallback((emergencyType, designation) => {
    if (emergencyType === 'common') return true
    if (emergencyType === 'fire'     && designation === 'fire_safety') return true
    if (emergencyType === 'medical'  && designation === 'medical')     return true
    if (emergencyType === 'security' && designation === 'security')    return true
    return false
  }, [])

  // ── Main Firebase setup ───────────────────────────────────────────────
  useEffect(() => {
    if (!userProfile?.staffProfile || !currentUser) return

    const { hotelCode, designation, isOnDuty: savedDuty } = userProfile.staffProfile
    setIsOnDuty(savedDuty || false)

    // 1. Fetch hotel config (room layout)
    const fetchHotel = async () => {
      try {
        const snap = await getDoc(doc(db, 'hotels', hotelCode))
        if (snap.exists()) setHotel(snap.data())
      } catch (err) {
        console.error('Hotel fetch error:', err)
      }
    }
    fetchHotel()

    // 2. Set presence in Realtime DB
    const presenceRef = ref(rtdb, `staff_presence/${hotelCode}/${currentUser.uid}`)
    set(presenceRef, {
      staffId:         currentUser.uid,
      name:            userProfile.name,
      designation,
      isOnline:        true,
      isOnDuty:        savedDuty || false,
      lastSeen:        Date.now(),
      currentIncident: null,
    })
    onDisconnect(presenceRef).update({ isOnline: false, lastSeen: Date.now() })

    // 3. Listen to all SOS signals for this hotel
    const sosRef = ref(rtdb, `sos/${hotelCode}`)
    onValue(sosRef, (snapshot) => {
      const data = snapshot.val() || {}
      setActiveSOS(data)

      // Check for NEW unassigned SOS matching my designation
      Object.values(data).forEach(sos => {
        if (
          sos.status === 'active' &&
          !sos.assignedStaffId &&
          isSOSForMe(sos.emergencyType, designation) &&
          isOnDutyRef.current
        ) {
          setNewSOSAlert(prev => {
            // Don't show if we already have a popup (same incident)
            if (prev?.roomNumber === sos.roomNumber) return prev
            return sos
          })
        }
      })

      // Track my own assigned incident
      const mine = Object.values(data).find(s => s.assignedStaffId === currentUser.uid)
      if (mine) {
        setMyIncident(mine)
        setAssignmentStep(mine.status === 'arrived' ? 2 : 1)
      } else {
        // Cleared from RTDB (resolved)
        setMyIncident(prev => {
          if (prev) setAssignmentStep(3)
          return null
        })
      }
    })

    // 4. Fetch incident history from Firestore
    const fetchHistory = async () => {
      try {
        const q = query(
          collection(db, 'incidents'),
          where('response.resolvedBy', '==', currentUser.uid)
        )
        const snap = await getDocs(q)
        setIncidentHistory(snap.docs.map(d => ({ id: d.id, ...d.data() })))
      } catch (err) {
        console.warn('History fetch error:', err)
      }
    }
    fetchHistory()

    return () => off(sosRef)
  }, [userProfile, currentUser, isSOSForMe])

  // ── Toggle duty ───────────────────────────────────────────────────────
  const toggleDuty = async (newDutyState) => {
    if (!userProfile?.staffProfile) return
    const hotelCode = userProfile.staffProfile.hotelCode
    setIsOnDuty(newDutyState)
    try {
      const presenceRef = ref(rtdb, `staff_presence/${hotelCode}/${currentUser.uid}`)
      await update(presenceRef, { isOnDuty: newDutyState })
      await updateDoc(doc(db, 'users', currentUser.uid), {
        'staffProfile.isOnDuty': newDutyState,
      })
      toast.success(newDutyState ? 'You are now On Duty' : 'You are now Off Duty')
    } catch (err) {
      toast.error('Failed to update duty status')
    }
  }

  // ── Accept SOS ─────────────────────────────────────────────────────────
  const acceptSOS = async (sosData) => {
    const hotelCode = userProfile.staffProfile.hotelCode
    setNewSOSAlert(null)
    try {
      const sosRef = ref(rtdb, `sos/${hotelCode}/${sosData.roomNumber}`)
      await update(sosRef, {
        status:               'assigned',
        assignedStaffId:      currentUser.uid,
        assignedStaffName:    userProfile.name,
        assignedDesignation:  userProfile.staffProfile.designation,
        acceptedAt:           Date.now(),
      })
      if (sosData.incidentId) {
        await updateDoc(doc(db, 'incidents', sosData.incidentId), {
          'response.assignedStaffId':     currentUser.uid,
          'response.assignedStaffName':   userProfile.name,
          'response.acceptedAt':          serverTimestamp(),
          status:                         'assigned',
          timeline: arrayUnion({
            event:     'STAFF_ACCEPTED',
            timestamp: Date.now(),
            actor:     currentUser.uid,
            actorName: userProfile.name,
          }),
        })
        await updateDoc(doc(db, 'users', currentUser.uid), {
          'staffProfile.activeIncidents': arrayUnion(sosData.incidentId),
        })
        const presenceRef = ref(rtdb, `staff_presence/${hotelCode}/${currentUser.uid}`)
        await update(presenceRef, { currentIncident: sosData.incidentId })

        const chatRef = ref(rtdb, `chats/${sosData.incidentId}`)
        const sysMsg = push(chatRef)
        await set(sysMsg, {
          messageId: sysMsg.key,
          type:      'system_message',
          message:   `${userProfile.name} has accepted this emergency and is on the way.`,
          timestamp: Date.now(),
        })
      }
      setMyIncident({ ...sosData, status: 'assigned' })
      setAssignmentStep(1)
      setTriggeredSeconds(0)
      setActiveTab('incident')
      toast.success(`Responding to Room ${sosData.roomNumber}`)
    } catch (err) {
      console.error('Accept SOS error:', err)
      toast.error('Failed to accept. Try again.')
    }
  }

  // ── Mark Arrived ──────────────────────────────────────────────────────
  const markArrived = async () => {
    if (!myIncident) return
    const hotelCode = userProfile.staffProfile.hotelCode
    try {
      const sosRef = ref(rtdb, `sos/${hotelCode}/${myIncident.roomNumber}`)
      await update(sosRef, { status: 'arrived', arrivedAt: Date.now() })
      if (myIncident.incidentId) {
        await updateDoc(doc(db, 'incidents', myIncident.incidentId), {
          'response.arrivedAt': serverTimestamp(),
          timeline: arrayUnion({
            event:     'STAFF_ARRIVED',
            timestamp: Date.now(),
            actor:     currentUser.uid,
          }),
        })
        const chatRef = ref(rtdb, `chats/${myIncident.incidentId}`)
        const msg = push(chatRef)
        await set(msg, {
          messageId: msg.key,
          type:      'system_message',
          message:   `${userProfile.name} has arrived at Room ${myIncident.roomNumber}.`,
          timestamp: Date.now(),
        })
      }
      setAssignmentStep(2)
      toast.success('Marked as arrived. Guest has been notified.')
    } catch (err) {
      toast.error('Failed to mark arrived')
    }
  }

  // ── Resolve Incident ──────────────────────────────────────────────────
  const resolveIncident = async () => {
    if (!myIncident || !resolveNotes.trim()) return
    const hotelCode = userProfile.staffProfile.hotelCode
    try {
      const sosRef = ref(rtdb, `sos/${hotelCode}/${myIncident.roomNumber}`)
      await remove(sosRef)
      if (myIncident.incidentId) {
        await updateDoc(doc(db, 'incidents', myIncident.incidentId), {
          'response.resolvedAt':      serverTimestamp(),
          'response.resolutionNotes': resolveNotes,
          'response.resolvedBy':      currentUser.uid,
          status:                     'resolved',
          timeline: arrayUnion({
            event:     'RESOLVED',
            timestamp: Date.now(),
            actor:     currentUser.uid,
          }),
        })
        await updateDoc(doc(db, 'users', currentUser.uid), {
          'staffProfile.activeIncidents': arrayRemove(myIncident.incidentId),
        })
        const presenceRef = ref(rtdb, `staff_presence/${hotelCode}/${currentUser.uid}`)
        await update(presenceRef, { currentIncident: null })
        const chatRef = ref(rtdb, `chats/${myIncident.incidentId}`)
        const msg = push(chatRef)
        await set(msg, {
          messageId: msg.key,
          type:      'system_message',
          message:   `Emergency resolved by ${userProfile.name}. ${resolveNotes}`,
          timestamp: Date.now(),
        })
      }
      setAssignmentStep(3)
      setShowResolveForm(false)
      toast.success('Emergency resolved and recorded!')
    } catch (err) {
      console.error('Resolve error:', err)
      toast.error('Failed to resolve. Try again.')
    }
  }

  const formatTriggeredTime = (secs) => {
    const m = Math.floor(secs / 60)
    const s = secs % 60
    return `${m}m ${s.toString().padStart(2, '0')}s ago`
  }

  const { darkMode } = useTheme()

  // ── Rooms from hotel config ────────────────────────────────────────────
  const floors = hotel?.floors || []

  // ── Room type from activeSOS ───────────────────────────────────────────
  const getRoomType = (room) => {
    const key = String(room)
    if (activeSOS[key]) return activeSOS[key].emergencyType || 'normal'
    return 'normal'
  }

  // ── Render ─────────────────────────────────────────────────────────────
  return (
    <div className={`flex min-h-screen transition-colors duration-300 ${darkMode ? 'bg-surface text-on-surface' : 'bg-slate-50 text-slate-800'}`}>
      {/* ── Sidebar ── */}
      <StaffSidebar
        isOnDuty={isOnDuty}
        onToggleDuty={toggleDuty}
        activeTab={activeTab}
        onTabChange={setActiveTab}
      />

      {/* ── Main Area ── */}
      <main className="flex-1 ml-64 flex flex-col h-screen overflow-hidden">
        <Header 
          title={{ 
            grid: 'Room Grid', 
            incident: 'My Assignment', 
            chat: 'Incident Chat', 
            group: 'Group Chat', 
            history: 'My History' 
          }[activeTab]} 
          subtitle={`${clock} • ${userProfile?.staffProfile?.hotelName || 'Crisis Bridge'}`}
        />

        <div className="flex-1 overflow-y-auto p-8">
          <div className="max-w-6xl mx-auto">
            <div className="tab-content" key={activeTab}>
              {activeTab === 'grid' && (
                <RoomGridTab floors={floors} activeSOS={activeSOS} getRoomType={getRoomType} darkMode={darkMode} />
              )}
              {activeTab === 'incident' && (
                <MyAssignmentTab
                  myIncident={myIncident}
                  step={assignmentStep}
                  triggeredSeconds={triggeredSeconds}
                  formatTime={formatTriggeredTime}
                  onMarkArrived={markArrived}
                  showResolveForm={showResolveForm}
                  setShowResolveForm={setShowResolveForm}
                  resolveNotes={resolveNotes}
                  setResolveNotes={setResolveNotes}
                  onResolve={resolveIncident}
                  darkMode={darkMode}
                />
              )}
              {activeTab === 'chat' && myIncident?.incidentId && (
                <ChatWindow
                  channelId={myIncident.incidentId}
                  currentUser={currentUser}
                  userProfile={userProfile}
                  title={`INCIDENT CHANNEL — ROOM ${myIncident.roomNumber} 🔥`}
                  isReadOnly={false}
                />
              )}
              {activeTab === 'chat' && !myIncident?.incidentId && (
                <div className="h-[60vh] flex flex-col items-center justify-center text-slate-500">
                  <span className="material-symbols-outlined text-6xl mb-4 opacity-20">forum</span>
                  <h3 className="text-xl font-bold mb-2">NO ACTIVE INCIDENT</h3>
                  <p>Accept an emergency to join the incident chat</p>
                </div>
              )}
              {activeTab === 'group' && (
                <ChatWindow
                  channelId={`staff_${userProfile?.staffProfile?.hotelCode}`}
                  currentUser={currentUser}
                  userProfile={userProfile}
                  title={`STAFF CHANNEL — ${userProfile?.staffProfile?.hotelName || 'HOTEL'} 📡`}
                  isReadOnly={false}
                />
              )}
              {activeTab === 'history' && (
                <IncidentHistoryTab
                  history={incidentHistory}
                  filter={historyFilter}
                  setFilter={setHistoryFilter}
                  expanded={expandedHistory}
                  setExpanded={setExpandedHistory}
                  darkMode={darkMode}
                />
              )}
            </div>
          </div>
        </div>
      </main>

      {/* ── SOS Popup ── */}
      {newSOSAlert && isOnDuty && (
        <SOSPopup
          sosData={newSOSAlert}
          onAccept={acceptSOS}
          onDecline={() => setNewSOSAlert(null)}
        />
      )}

      {/* ── Toast ── */}
      {toast_msg && <div className="toast">{toast_msg}</div>}
    </div>
  )
}


// ════════════════════════════════════════
// ROOM GRID TAB
// ════════════════════════════════════════
function RoomGridTab({ floors, activeSOS, getRoomType }) {
  const [hover, setHover] = useState(null)

  const getTooltip = (room) => {
    const key = String(room)
    const sos = activeSOS[key]
    if (sos) {
      const minutesAgo = sos.triggeredAt
        ? Math.floor((Date.now() - sos.triggeredAt) / 60000)
        : '?'
      return `Room ${room} — ${(sos.emergencyType || 'SOS').toUpperCase()} — ${minutesAgo}m ago`
    }
    return `Room ${room} — Available`
  }

  if (!floors.length) {
    return (
      <div className="animate-pulse">
        <div className="mb-8">
          <h2 className="text-2xl font-black tracking-tight mb-2">LIVE HOTEL GRID</h2>
          <span className="text-slate-500 font-medium">Loading hotel layout...</span>
        </div>
        <div className="h-64 flex flex-col items-center justify-center bg-slate-100 dark:bg-surface-container-low rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800">
          <div className="text-4xl mb-4">🏨</div>
          <h3 className="font-bold">LOADING HOTEL DATA</h3>
          <p className="text-sm text-slate-500">Fetching room configuration...</p>
        </div>
      </div>
    )
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-black tracking-tight mb-2">LIVE HOTEL GRID</h2>
          <span className="text-slate-500 font-medium">Last updated: just now</span>
        </div>
        <div className="flex gap-2">
           <div className="px-3 py-1 bg-emerald-500/10 text-emerald-500 rounded-full text-xs font-bold ring-1 ring-emerald-500/20 flex items-center gap-1.5">
             <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse" />
             Live Monitoring
           </div>
        </div>
      </div>

      <div className="space-y-12">
        {floors.map((f) => (
          <div className="floor-section" key={f.floor}>
            <div className="flex items-center gap-4 mb-6">
              <span className="text-sm font-black text-slate-400 dark:text-slate-500 tracking-[0.2em] uppercase">
                FLOOR {f.floor}
              </span>
              <div className="flex-1 h-px bg-slate-200 dark:bg-slate-800" />
            </div>
            <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-6 lg:grid-cols-8 gap-4">
              {(f.rooms || []).map((room) => {
                const type = getRoomType(room)
                const isSOS = type !== 'normal'
                
                return (
                  <div
                    key={room}
                    className={`relative aspect-square rounded-2xl flex items-center justify-center text-lg font-bold transition-all duration-300 cursor-pointer group px-4 text-center ${
                      type === 'normal' 
                        ? 'bg-slate-100 dark:bg-surface-container-low text-slate-400 dark:text-slate-600 hover:scale-105 hover:bg-slate-200 dark:hover:bg-surface-bright'
                        : type === 'fire'
                        ? 'bg-red-500 text-white shadow-lg shadow-red-500/40 animate-pulse'
                        : type === 'medical'
                        ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/40 animate-pulse'
                        : type === 'security'
                        ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/40 animate-pulse'
                        : 'bg-purple-500 text-white shadow-lg shadow-purple-500/40 animate-pulse'
                    }`}
                    onMouseEnter={() => setHover(room)}
                    onMouseLeave={() => setHover(null)}
                  >
                    {room}
                    {hover === room && (
                      <div className="absolute -top-12 left-1/2 -translate-x-1/2 bg-slate-900 text-white text-[10px] px-3 py-1.5 rounded-lg whitespace-nowrap z-50 shadow-xl font-medium animate-in fade-in zoom-in duration-200">
                        {getTooltip(room)}
                        <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-2 h-2 bg-slate-900 rotate-45" />
                      </div>
                    )}
                  </div>
                )
              })}
            </div>
          </div>
        ))}
      </div>

      <div className="mt-12 p-6 bg-slate-100 dark:bg-surface-container-low rounded-2xl flex flex-wrap gap-6 items-center border border-slate-200 dark:border-slate-800 transition-colors">
        <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mr-2">Legend</div>
        <div className="flex items-center gap-2 text-xs font-bold text-slate-600 dark:text-slate-400">
          <div className="w-3 h-3 bg-red-500 rounded-full shadow-sm shadow-red-500/50" /> FIRE
        </div>
        <div className="flex items-center gap-2 text-xs font-bold text-slate-600 dark:text-slate-400">
          <div className="w-3 h-3 bg-emerald-500 rounded-full shadow-sm shadow-emerald-500/50" /> MEDICAL
        </div>
        <div className="flex items-center gap-2 text-xs font-bold text-slate-600 dark:text-slate-400">
          <div className="w-3 h-3 bg-amber-500 rounded-full shadow-sm shadow-amber-500/50" /> SECURITY
        </div>
        <div className="flex items-center gap-2 text-xs font-bold text-slate-600 dark:text-slate-400">
          <div className="w-3 h-3 bg-purple-500 rounded-full shadow-sm shadow-purple-500/50" /> COMMON
        </div>
        <div className="flex items-center gap-2 text-xs font-bold text-slate-600 dark:text-slate-400">
          <div className="w-3 h-3 bg-slate-300 dark:bg-slate-700 rounded-full" /> AVAILABLE
        </div>
      </div>
    </div>
  )
}


// ════════════════════════════════════════
// MY ASSIGNMENT TAB
// ════════════════════════════════════════
function MyAssignmentTab({ myIncident, step, triggeredSeconds, formatTime, onMarkArrived, showResolveForm, setShowResolveForm, resolveNotes, setResolveNotes, onResolve, darkMode }) {
  if (!myIncident && step !== 3) {
    return (
      <div className="h-[60vh] flex flex-col items-center justify-center text-slate-500">
        <div className="w-20 h-20 bg-slate-100 dark:bg-surface-container-high rounded-full flex items-center justify-center mb-6 shadow-inner">
          <span className="material-symbols-outlined text-4xl opacity-30">shield</span>
        </div>
        <h3 className="text-xl font-bold mb-2">NO ACTIVE ASSIGNMENT</h3>
        <p>Stay on duty to receive emergency alerts</p>
      </div>
    )
  }

  if (step === 3) {
    return (
      <div className="max-w-2xl mx-auto py-12">
        <div className="bg-emerald-500/10 dark:bg-emerald-500/5 border border-emerald-500/20 rounded-3xl p-12 text-center mb-8">
          <div className="w-20 h-20 bg-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 shadow-xl shadow-emerald-500/30">
            <span className="material-symbols-outlined text-white text-4xl">check_circle</span>
          </div>
          <h2 className="text-3xl font-black text-emerald-600 dark:text-emerald-400 mb-2">EMERGENCY RESOLVED</h2>
          <p className="text-emerald-600/70 dark:text-emerald-400/60 font-medium">Room resolved successfully. Good work!</p>
        </div>
        <div className="bg-white dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-3xl p-8 transition-colors">
          <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-8 text-center">Response Timeline</h4>
          <div className="space-y-6">
            {['SOS TRIGGERED', 'ASSIGNED', 'ARRIVED', 'RESOLVED'].map((label, i) => (
              <TimelineItem key={i} label={label} state="resolved" isLast={i === 3} />
            ))}
          </div>
        </div>
      </div>
    )
  }

  const emergency = getEmergency(myIncident?.emergencyType)
  const steps = ['SOS TRIGGERED', 'ASSIGNED', 'ARRIVED', 'RESOLVED']

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <div className={`rounded-3xl p-8 flex items-center gap-6 shadow-lg shadow-black/5 transition-all ${
        myIncident.emergencyType === 'fire' 
          ? 'bg-gradient-to-br from-red-500 to-orange-600 text-white' 
          : myIncident.emergencyType === 'medical'
          ? 'bg-gradient-to-br from-emerald-500 to-teal-600 text-white'
          : myIncident.emergencyType === 'security'
          ? 'bg-gradient-to-br from-amber-500 to-orange-500 text-white'
          : 'bg-gradient-to-br from-purple-500 to-indigo-600 text-white'
      }`}>
        <div className="w-16 h-16 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center text-4xl shadow-inner">
          {emergency.icon}
        </div>
        <div className="flex-1">
          <h2 className="text-2xl font-black tracking-tight uppercase leading-none mb-1">{emergency.label} EMERGENCY</h2>
          <p className="opacity-90 font-medium text-sm">Action required immediately</p>
        </div>
        <div className="px-4 py-2 bg-white/10 backdrop-blur-md rounded-xl text-[10px] font-black tracking-widest uppercase border border-white/20">
          Response Active
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-3xl p-8 transition-colors">
           <div className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Location Info</div>
           <div className="flex items-end gap-3 mb-1">
             <span className="text-5xl font-black text-slate-800 dark:text-white transition-colors">{myIncident.roomNumber}</span>
             <span className="text-slate-400 font-bold mb-1.5 uppercase text-xs tracking-wider">Room</span>
           </div>
           <div className="text-lg font-bold text-blue-500 mb-6">FLOOR {myIncident.floor || '—'}</div>
           
           <div className="space-y-4 pt-6 border-t border-slate-100 dark:border-slate-800 transition-colors">
              <div className="flex items-center justify-between">
                <span className="text-xs font-bold text-slate-400 uppercase">Guest</span>
                <span className="font-bold text-sm text-slate-800 dark:text-slate-200 transition-colors">{myIncident.guestName || 'Unknown'}</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-xs font-bold text-slate-400 uppercase">Phone</span>
                <span className="font-mono text-sm text-slate-800 dark:text-slate-200 transition-colors">{myIncident.guestPhone || 'N/A'}</span>
              </div>
           </div>
        </div>

        <div className="bg-white dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-3xl p-8 transition-colors flex flex-col justify-between">
          <div>
            <div className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Response Status</div>
            <div className="text-3xl font-black text-slate-800 dark:text-white transition-colors mb-2">
              {formatTime(triggeredSeconds)}
            </div>
            <p className="text-xs text-slate-500 font-medium">Time elapsed since triggered</p>
          </div>
          
          <div className="mt-8 flex items-center gap-3 px-4 py-3 bg-blue-500/10 rounded-2xl border border-blue-500/20">
            <span className="w-2 h-2 bg-blue-500 rounded-full animate-pulse" />
            <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Assigned to you</span>
          </div>
        </div>
      </div>

      <div className="bg-white dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-3xl p-8 transition-colors">
        <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-8">Process Status</h4>
        <div className="space-y-6">
          {steps.map((label, i) => {
            let state = 'pending'
            if (i <= step) state = 'completed'
            return <TimelineItem key={i} label={label} state={state} isLast={i === 3} />
          })}
        </div>
      </div>

      <div className="space-y-4">
        {step === 1 && (
          <button 
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-5 rounded-2xl transition-all shadow-xl shadow-blue-500/20 flex items-center justify-center gap-3 active:scale-[0.98]" 
            onClick={onMarkArrived}
          >
            <span className="material-symbols-outlined">how_to_reg</span>
            MARK ARRIVED AT ROOM
          </button>
        )}
        {step === 2 && !showResolveForm && (
          <button 
            className="w-full bg-red-600 hover:bg-red-700 text-white font-black py-5 rounded-2xl transition-all shadow-xl shadow-red-500/20 flex items-center justify-center gap-3 active:scale-[0.98]" 
            onClick={() => setShowResolveForm(true)}
          >
            <span className="material-symbols-outlined">check_circle</span>
            RESOLVE EMERGENCY
          </button>
        )}
        {showResolveForm && (
          <div className="bg-slate-100 dark:bg-surface-container-highest rounded-3xl p-6 transition-colors shadow-inner space-y-4 animate-in fade-in slide-in-from-bottom-4">
            <div className="text-xs font-bold text-slate-500 uppercase px-2">Resolution Findings</div>
            <textarea
              className="w-full bg-white dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-2xl p-4 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all min-h-[120px] resize-none"
              placeholder="Describe the action taken and final outcome..."
              value={resolveNotes}
              onChange={(e) => setResolveNotes(e.target.value)}
            />
            <div className="flex gap-3">
              <button 
                className="flex-1 bg-slate-200 dark:bg-slate-800 hover:bg-slate-300 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400 font-bold py-3 rounded-xl transition-colors"
                onClick={() => setShowResolveForm(false)}
              >
                Cancel
              </button>
              <button 
                className="flex-2 bg-emerald-600 hover:bg-emerald-700 text-white font-black py-3 px-8 rounded-xl transition-all shadow-lg active:scale-[0.98]" 
                onClick={onResolve}
              >
                Confirm Resolution
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

function TimelineItem({ label, state, isLast }) {
  const isDone = state === 'completed' || state === 'resolved'
  return (
    <div className="relative flex items-center gap-4 group">
       {!isLast && (
         <div className={`absolute left-[11px] top-6 w-0.5 h-10 transition-colors ${isDone ? 'bg-blue-500' : 'bg-slate-200 dark:bg-slate-800'}`} />
       )}
       <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] transition-all z-10 border-2 ${
         isDone 
          ? 'bg-blue-500 border-blue-500 text-white shadow-lg shadow-blue-500/20' 
          : 'bg-white dark:bg-surface-container-low border-slate-200 dark:border-slate-800 text-slate-300'
       }`}>
         {isDone ? '✓' : ''}
       </div>
       <span className={`text-sm font-bold tracking-tight transition-colors ${isDone ? 'text-slate-800 dark:text-slate-200' : 'text-slate-400'}`}>
         {label}
       </span>
    </div>
  )
}


// ════════════════════════════════════════
// INCIDENT HISTORY TAB
// ════════════════════════════════════════
function IncidentHistoryTab({ history, filter, setFilter, expanded, setExpanded, darkMode }) {
  const filtered = history.filter(item => {
    if (filter.type !== 'all' && item.emergencyType !== filter.type) return false
    if (filter.status !== 'all' && item.status !== filter.status) return false
    return true
  })

  const resolvedCount = history.filter(i => i.status === 'resolved').length

  const getEmergencyStyles = (type) => {
    const styles = {
      fire:     'bg-red-500/10 text-red-600 dark:text-red-400 ring-red-500/20',
      medical:  'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 ring-emerald-500/20',
      security: 'bg-amber-500/10 text-amber-600 dark:text-amber-400 ring-amber-500/20',
      common:   'bg-purple-500/10 text-purple-600 dark:text-purple-400 ring-purple-500/20',
    }
    return styles[type] || 'bg-slate-500/10 text-slate-600 ring-slate-500/20'
  }

  const getAccentColor = (type) => {
    const styles = {
      fire:     'bg-red-500',
      medical:  'bg-emerald-500',
      security: 'bg-amber-500',
      common:   'bg-purple-500',
    }
    return styles[type] || 'bg-slate-500'
  }

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-black tracking-tight mb-2">INCIDENT HISTORY</h2>
          <span className="text-slate-500 font-medium">{resolvedCount} TOTAL RESOLVED</span>
        </div>
        
        <div className="flex gap-3">
          <select
            className="bg-white dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-xl px-4 py-2 text-sm font-bold text-slate-600 dark:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-sm"
            value={filter.type}
            onChange={(e) => setFilter(prev => ({ ...prev, type: e.target.value }))}
          >
            <option value="all">All Types</option>
            <option value="fire">Fire</option>
            <option value="medical">Medical</option>
            <option value="security">Security</option>
            <option value="common">Common</option>
          </select>
          <select
            className="bg-white dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-xl px-4 py-2 text-sm font-bold text-slate-600 dark:text-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all shadow-sm"
            value={filter.status}
            onChange={(e) => setFilter(prev => ({ ...prev, status: e.target.value }))}
          >
            <option value="all">All Status</option>
            <option value="resolved">Resolved</option>
            <option value="escalated">Escalated</option>
          </select>
        </div>
      </div>

      <div className="space-y-4">
        {filtered.map((item) => (
          <div key={item.id} className="group">
            <div
              className={`bg-white dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-2xl overflow-hidden transition-all duration-300 cursor-pointer hover:shadow-lg hover:-translate-y-1 ${expanded === item.id ? 'ring-2 ring-blue-500 dark:ring-blue-400' : ''}`}
              onClick={() => setExpanded(expanded === item.id ? null : item.id)}
            >
              <div className="flex items-stretch h-24">
                <div className={`w-2 transition-colors duration-300 ${getAccentColor(item.emergencyType || item.type)}`} />
                <div className="flex-1 px-8 flex items-center justify-between">
                  <div className="flex items-center gap-6">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black tracking-widest uppercase ring-1 ${getEmergencyStyles(item.emergencyType || item.type)}`}>
                      {(item.emergencyType || item.type || 'unknown')}
                    </span>
                    <div>
                      <div className="flex items-baseline gap-2">
                        <span className="text-xl font-black text-slate-800 dark:text-white transition-colors">{item.roomNumber || item.room}</span>
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Room</span>
                      </div>
                      <div className="text-xs text-slate-500 font-medium">
                        {item.guestName || item.guest} • {item.date || item.createdAt?.toDate?.()?.toLocaleDateString() || 'Recently'}
                      </div>
                    </div>
                  </div>
                  
                  <div className="flex items-center gap-8">
                    <div className="hidden sm:block text-right">
                      <div className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Response Time</div>
                      <div className="text-sm font-bold text-slate-700 dark:text-slate-300">{item.response?.resolutionTime || '8m 24s'}</div>
                    </div>
                    <span className={`px-4 py-1.5 rounded-xl text-[10px] font-black tracking-widest uppercase shadow-sm ${item.status === 'resolved' ? 'bg-emerald-500 text-white' : 'bg-amber-500 text-white'}`}>
                      {(item.status || 'unknown')}
                    </span>
                    <span className={`material-symbols-outlined transition-transform duration-300 ${expanded === item.id ? 'rotate-180' : ''}`}>
                      expand_more
                    </span>
                  </div>
                </div>
              </div>
              
              {expanded === item.id && (
                <div className="px-8 py-6 bg-slate-50/50 dark:bg-slate-900/50 border-t border-slate-100 dark:border-slate-800 animate-in slide-in-from-top-4 duration-300">
                  <div className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Resolution Notes</div>
                  <div className="p-4 bg-white dark:bg-surface-container-highest rounded-xl border border-slate-200 dark:border-slate-800 text-sm text-slate-600 dark:text-slate-300 shadow-inner leading-relaxed transition-colors">
                    {item.response?.resolutionNotes || item.notes || 'No detailed resolution notes were recorded for this incident.'}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {filtered.length === 0 && (
          <div className="h-[40vh] flex flex-col items-center justify-center text-slate-500 bg-slate-100 dark:bg-surface-container-low rounded-3xl border-2 border-dashed border-slate-200 dark:border-slate-800">
            <span className="material-symbols-outlined text-4xl mb-4 opacity-20">history</span>
