import { useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { useAuth } from '../../contexts/AuthContext'
import { doc, onSnapshot } from 'firebase/firestore'
import { db } from '../../firebase/config'
import { useTheme } from '../../contexts/ThemeContext'

function timeAgoFromDate(ts) {
  if (!ts) return 'Recently'
  const d = ts.toDate ? ts.toDate() : new Date(ts)
  const diff = Math.floor((Date.now() - d.getTime()) / 1000)
  if (diff < 60) return `${diff} seconds ago`
  if (diff < 3600) return `${Math.floor(diff / 60)} minutes ago`
  if (diff < 86400) return `${Math.floor(diff / 3600)} hours ago`
  return `${Math.floor(diff / 86400)} days ago`
}

export default function StaffPending() {
  const { currentUser, userProfile, refreshProfile } = useAuth()
  const navigate = useNavigate()

  useEffect(() => {
    if (!currentUser) return

    const unsub = onSnapshot(doc(db, 'users', currentUser.uid), (snap) => {
      const data = snap.data()
      if (data?.staffProfile?.isApproved === true) {
        refreshProfile()
        navigate('/staff/dashboard')
      }
    })

    return () => unsub()
  }, [currentUser])

  const sp = userProfile?.staffProfile
  const designationMap = {
    fire_safety: '🔥 Fire Safety Officer',
    medical:     '🏥 Medical Responder',
    security:    '🛡️ Security Personnel',
    general:     '👷 General Staff',
  }

  const { darkMode, toggleDarkMode } = useTheme()

  return (
    <div className={`min-h-screen flex items-center justify-center p-6 transition-colors duration-300 ${darkMode ? 'bg-surface text-on-surface' : 'bg-slate-50 text-slate-800'}`}>
      <div className="absolute top-8 right-8">
        <button 
          onClick={toggleDarkMode}
          className="p-3 rounded-full bg-white dark:bg-surface-container-high text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-surface-bright transition flex items-center justify-center shadow-lg border border-slate-200 dark:border-slate-700"
          title="Toggle Dark Mode"
        >
          <span className="material-symbols-outlined">
            {darkMode ? 'light_mode' : 'dark_mode'}
          </span>
        </button>
      </div>

      <div className="w-full max-w-md">

        {/* Icon + Heading */}
        <div className="text-center mb-8">
          <div className="text-7xl mb-4 animate-bounce">⏳</div>
          <h1 className={`text-2xl font-black mb-2 transition-colors ${darkMode ? 'text-white' : 'text-slate-900'}`}>Account Pending Approval</h1>
          <p className="text-slate-500 dark:text-on-surface-variant text-sm leading-relaxed transition-colors">
            Your hotel admin needs to approve your account before you can access the dashboard.
          </p>
        </div>

        {/* Info Box */}
        <div className={`rounded-3xl p-6 mb-6 border transition-colors ${
          darkMode 
            ? 'bg-amber-500/10 border-amber-500/20' 
            : 'bg-amber-50 border-amber-100 shadow-sm shadow-amber-500/5'
        }`}>
          <h3 className={`font-bold text-[10px] uppercase tracking-[0.2em] mb-4 transition-colors ${darkMode ? 'text-amber-400' : 'text-amber-600'}`}>
            Your Submission
          </h3>
          <div className="space-y-4">
            <InfoRow label="Hotel" value={sp?.hotelName || '—'} darkMode={darkMode} />
            <InfoRow label="Hotel Code" value={sp?.hotelCode || '—'} darkMode={darkMode} />
            <InfoRow label="Designation" value={designationMap[sp?.designation] || sp?.designation || '—'} darkMode={darkMode} />
            <InfoRow label="Submitted" value={timeAgoFromDate(userProfile?.createdAt)} darkMode={darkMode} />
            <InfoRow label="Status" value={
              <span className={`text-[10px] font-black tracking-widest px-3 py-1 rounded-full transition-colors ${
                darkMode ? 'bg-amber-500/20 text-amber-400' : 'bg-amber-100 text-amber-700'
              }`}>
                PENDING REVIEW
              </span>
            } darkMode={darkMode} />
          </div>
        </div>

        {/* Auto-refresh note */}
        <div className="bg-slate-100 dark:bg-surface-container-low border border-slate-200 dark:border-slate-800 rounded-2xl p-4 mb-6 text-center transition-colors">
          <div className="flex items-center justify-center gap-3 text-slate-500 dark:text-on-surface-variant text-[11px] font-bold uppercase tracking-wider">
            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-lg shadow-emerald-500/50" />
            <span>Automatic monitoring enabled</span>
          </div>
        </div>

        {/* Back button */}
        <button
          onClick={() => navigate('/')}
          className={`w-full py-4 rounded-2xl font-black text-sm transition-all active:scale-[0.98] ${
            darkMode 
              ? 'bg-slate-800 hover:bg-slate-700 text-white shadow-xl shadow-black/20' 
              : 'bg-white hover:bg-slate-100 text-slate-700 shadow-lg shadow-slate-200/50 border border-slate-200'
          }`}
        >
