// src/services/hotelService.js
// Hotel lookup and guest check-in / check-out logic

import { getHotelDoc, updateUserDoc, serverTimestamp } from '../firebase/firestore'

/**
 * Validate that a hotel code exists in Firestore.
 * Returns { valid: true, hotelData } or { valid: false, error }
 */
export const validateHotelCode = async (hotelCode) => {
  try {
    const snap = await getHotelDoc(hotelCode)
    if (!snap.exists()) {
      return { valid: false, error: 'Hotel code not found. Please double-check with your front desk.' }
    }
    return { valid: true, hotelData: snap.data() }
  } catch (err) {
    return { valid: false, error: 'Network error. Please try again.' }
  }
}

/**
 * Register a guest as currently staying.
 * Updates the user's guestProfile in Firestore.
 */
export const checkInGuest = async (uid, { hotelCode, hotelName, roomNumber, guestCount }) => {
  await updateUserDoc(uid, {
    'guestProfile.isCurrentlyStaying': true,
    'guestProfile.currentHotelCode':   hotelCode.toUpperCase(),
    'guestProfile.currentHotelName':   hotelName,
    'guestProfile.currentRoomNumber':  roomNumber,
    'guestProfile.numberOfGuests':     guestCount,
    'guestProfile.checkInDate':        serverTimestamp(),
    'guestProfile.checkOutDate':       null,
  })
}

/**
 * Check the guest out: clears the active stay fields.
 */
export const checkOutGuest = async (uid) => {
  await updateUserDoc(uid, {
    'guestProfile.isCurrentlyStaying': false,
    'guestProfile.currentHotelCode':   null,
    'guestProfile.currentHotelName':   null,
    'guestProfile.currentRoomNumber':  null,
    'guestProfile.checkOutDate':       serverTimestamp(),
  })
}

// src/services/sosService.js
// Full SOS trigger, listener, and resolution logic

import { writeSOS, clearSOS, patchSOS, pushChatMessage } from '../firebase/realtime'
import { createIncidentDoc, updateIncidentDoc, appendIncidentTimeline } from '../firebase/firestore'
import { buildIncidentId } from '../utils/helpers'

/**
 * Trigger an SOS from the guest side.
 *
 * Steps:
 *   1. Write live SOS record to Realtime DB → staff/admin dashboards glow
 *   2. Create permanent incident record in Firestore
 *   3. Post a system message to the auto-created chat room
 *
 * @returns {string} incidentId
 */
export const triggerSOS = async (currentUser, userProfile, emergencyType) => {
  const hotelCode  = userProfile.guestProfile.currentHotelCode
  const roomNumber = userProfile.guestProfile.currentRoomNumber
  const floor      = roomNumber?.length >= 3 ? roomNumber[0] : '1'
  const incidentId = buildIncidentId(roomNumber, emergencyType)

  // ── 1. Write to Realtime DB ────────────────────────────────────
  await writeSOS(hotelCode, roomNumber, {
    incidentId,
    guestId:           currentUser.uid,
    guestName:         userProfile.name,
    guestPhone:        userProfile.phone || '',
    roomNumber,
    floor,
    emergencyType,
    hotelCode,
    numberOfGuests:    userProfile.guestProfile.numberOfGuests || 1,
    triggeredAt:       Date.now(),
    status:            'active',
    assignedStaffId:   null,
    assignedStaffName: null,
  })

  // ── 2. Create Firestore incident record ───────────────────────
  await createIncidentDoc(incidentId, {
    incidentId,
    hotelCode,
    guest: {
      userId:         currentUser.uid,
      name:           userProfile.name,
      phone:          userProfile.phone || '',
      roomNumber,
      floor,
      numberOfGuests: userProfile.guestProfile.numberOfGuests || 1,
    },
    emergency: {
      type:        emergencyType,
      triggeredAt: Date.now(),
      description: '',
      severity:    'critical',
    },
    response: {
      assignedStaffId:          null,
      assignedStaffName:        null,
      assignedStaffDesignation: null,
      acceptedAt:               null,
      arrivedAt:                null,
      resolvedAt:               null,
      resolutionNotes:          '',
    },
    timeline: [{
      event:     'SOS_TRIGGERED',
      timestamp: Date.now(),
      actor:     currentUser.uid,
    }],
    chatRoomId: incidentId,
    status: 'active',
  })

  // ── 3. Create chat room with a system message ─────────────────
  await pushChatMessage(incidentId, {
    type:        'system_message',
    senderRole:  'system',
    senderName:  'Crisis Bridge',
    message:     `🚨 Emergency alert by ${userProfile.name} in Room ${roomNumber}. Type: ${emergencyType.toUpperCase()}. Help is being dispatched.`,
    timestamp:   Date.now(),
  })

  return incidentId
}

/**
 * Resolve an active SOS (can be called by staff or admin, exposed here for future guest "cancel" flow).
 * Removes the Realtime DB entry and updates Firestore status.
 */
export const resolveSOSFromGuest = async (hotelCode, roomNumber, incidentId, actorId) => {
  await clearSOS(hotelCode, roomNumber)
  await updateIncidentDoc(incidentId, { status: 'resolved' })
  await appendIncidentTimeline(incidentId, {
    event: 'RESOLVED',
    actor: actorId,
  })
}
